@mixin flex {
  display: flex;
  align-items: center;
}

body,
html {
  width: 100%;
  height: 100vh;
  font-family: "Arial";
  margin: 0px;
  overflow: hidden;
  font-size: 14px;
}
ul {
  padding: 0px;
}
li {
  list-style: none;
}
.hide {
  display: none;
}
header {
  padding: 10px;
  height: 70px;
  @include flex;
  justify-content: space-between;
  background: #101e2b;
  .wrapperLogo,
  .wrapperExitAction {
    @include flex;
  }
  .logo {
    margin-left: 30px;
  }
  .icon-search {
    margin-left: 50px;
  }
  .search {
    margin-left: 20px;
    background: #101e2b;
    border: none;
    &:focus-visible {
      outline: none;
      border: none;
    }
  }
  .notification {
    margin-right: 30px;
    position: relative;
    img {
      color: #ffffff;
    }
    &:after {
      content: url("../assets/notification-check.svg");
      position: absolute;
      color: #bf356f;
      width: 9px;
      height: 9px;
      border-radius: 50%;
      top: -10px;
    }
  }
  .user {
    margin-right: 10px;
    box-shadow: 0px 0px 16px rgb(153 164 181 / 20%);
    border-radius: 50%;
  }
  .arrow-down {
    background: none;
    border: none;
  }
  .exit {
    width: 26px;
    height: 26px;
    background: #4680d9;
    border-radius: 50px;
    @include flex;
    margin: 0px 10px 0px 20px;
    justify-content: center;
    cursor: pointer;
  }
}
.container {
  @include flex;
  background: #0a151f;
  height: 90vh;
  padding: 24px;
  aside {
    width: 420px;
    height: 83vh;
    background: #101e2b;
    border-radius: 10px;
    box-shadow: 0px 0px 16px rgba(153, 164, 181, 0.4);
    h2 {
      margin: 0;
      padding: 15px;
      color: #ffffff;
    }
  }
  .users-blocks {
    padding: 15px;
    border-bottom: 1px solid #0a151f;
    .wrapperUsersName,
    .wrapperMessageSnippet {
      justify-content: space-between;
      height: 37px;
      @include flex;
      span {
        font-weight: 700;
        font-size: 16px;
        color: #ffffff;
      }
      .userName,
      .time {
        @include flex;
      }
      .userName {
        img {
          margin-right: 10px;
        }
      }
      .time {
        color: #938383;
      }
      .snippet {
        color: #a0a0a0;
        font-size: 15px;
      }
      .count {
        background: #ec2e67;
        width: 23px;
        height: 23px;
        border-radius: 50px;
        @include flex;
        justify-content: center;
        color: #ffffff;
      }
    }
  }
  .active {
    background: #0a151f;
    border-right: 3px solid#4680D9;
    border-radius: 10px;
  }
  .chat {
    width: 100%;
    height: 83vh;
    background: #0a151f;
    border-radius: 10px;
    margin-left: 30px;
    box-shadow: 0px 0px 16px rgba(153, 164, 181, 0.2);
    .chatHeader {
      background: #101e2b;
      height: 60px;
      border-top-left-radius: 10px;
      border-top-right-radius: 10px;
      @include flex;
      padding: 0px 20px;
      font-weight: 700;
      font-size: 16px;
      span {
        margin-left: 20px;
        color: #ffffff;
      }
    }
    .chatBody {
      @include flex;
      flex-direction: column;
      padding: 20px;
      color: #ffffff;
      .entryMessage {
        background: #101e2b;
        height: auto;
        align-self: start;
        padding: 10px;
        min-width: 350px;
        max-width: 700px;
        border-top-left-radius: 10px;
        border-top-right-radius: 10px;
        border-bottom-right-radius: 10px;
        p {
          line-height: 20px;
        }
      }
      .authorMessage {
        background: #32597e;
        height: auto;
        align-self: end;
        padding: 10px;
        min-width: 350px;
        max-width: 700px;
        border-top-left-radius: 10px;
        border-top-right-radius: 10px;
        border-bottom-left-radius: 10px;
        p {
          line-height: 20px;
        }
      }
      .addMessage {
        @include flex;
        position: absolute;
        bottom:0;
        margin-bottom: 70px;;
        .messageField {
          width: 894px;
          height: 63px;
          background: #13212e;
          border-radius: 10px;
          box-shadow: 0px 0px 16px rgb(153 164 181 / 20%);
          outline: none;
          border: none;
          margin-left: 35px;
          padding: 10px;
          color: #ffffff;          
        }
        label {
          position: absolute;
          right: 20px;
          z-index: 2;
          border: none;
          top: 19px;
          cursor: pointer;
          color: white;
          width: 45px;
          height: 42px;
          background: #4680d9;
          border-radius: 10px;
          @include flex;
          justify-content: center;
        }
      }
    }
  }
}
